const perDocLimit = input.model_strategy === "simple_fast" ? 2500 : 4000;
const totalLimit = input.model_strategy === "simple_fast" ? 9000 : 15000;

function cleanText(value) {
  return String(value || "")
    .replace(/\r\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

let remaining = totalLimit;
const sections = [];

for (const doc of docs) {
  if (remaining <= 0) break;

  const body = cleanText(doc.content).slice(0, Math.min(perDocLimit, remaining));
  if (!body) continue;

  const section = [
    `[doc_id: ${doc.doc_id || doc.title || "unknown"}]`,
    `Title: ${doc.title || ""}`,
    `Module: ${doc.module || ""}`,
    `Type: ${doc.type || ""}`,
    `Status: ${doc.status || ""}`,
    `Authority: ${doc.authority || ""}`,
    "",
    body,
  ].join("\n");

  sections.push(section);
  remaining -= section.length;
}

const errors = Array.isArray(input.kb_doc_fetch_errors) ? input.kb_doc_fetch_errors : [];
let kb_context = sections.join("\n\n---\n\n").trim();

